const SANITY_PROJECT="ehwjnjr2",SANITY_DATASET="production",SANITY_API_VER="2024-01-01",SANITY_CDN=`https://${SANITY_PROJECT}.apicdn.sanity.io/v${SANITY_API_VER}/data/query/${SANITY_DATASET}`;async function sanityFetch(e,a={}){let t=`${SANITY_CDN}?query=${encodeURIComponent(e)}`;for(const[r,s]of Object.entries(a))t+=`&$${encodeURIComponent(r)}=${encodeURIComponent(JSON.stringify(s))}`;try{const r=await fetch(t);if(!r.ok)throw new Error(`HTTP ${r.status}`);return(await r.json())?.result??null}catch(r){return console.warn("[CMS] Fetch failed:",r.message),null}}function sanityImageUrl(e,{width:a}={}){if(!e)return"";const t=e.split("-"),r=t.pop(),s=t.pop(),c=t.slice(1).join("-");let o=`https://cdn.sanity.io/images/${SANITY_PROJECT}/${SANITY_DATASET}/${c}-${s}.${r}`;return a&&(o+=`?w=${a}&auto=format`),o}window.CMS={fetchNews(){return sanityFetch(`*[_type == "newsArticle"] | order(date desc) {
      _id,
      "id": slug.current,
      title, titleDe,
      category,
      categoryLabel, categoryLabelDe,
      "date": date,
      "dateISO": date,
      "imageUrl": image.asset->url + "?w=900&auto=format&q=80",
      alt,
      excerpt, excerptDe,
      content, contentDe
    }`)},fetchArticleBySlug(e,a="en"){const t=a==="de";return sanityFetch(`*[_type == "newsArticle" && slug.current == $slug][0] {
      _id,
      "id": slug.current,
      "title": ${t?"coalesce(titleDe, title)":"title"},
      category,
      "categoryLabel": ${t?"coalesce(categoryLabelDe, categoryLabel)":"categoryLabel"},
      "date": date,
      "dateISO": date,
      "imageUrl": image.asset->url + "?w=900&auto=format&q=80",
      alt,
      "excerpt": ${t?"coalesce(excerptDe, excerpt)":"excerpt"},
      "content": ${t?"select(defined(contentDe) => array::join(contentDe[_type=='block']{'h':select(style=='h2'=>'<h2>'+array::join(children[].text,'')+ '</h2>',style=='h3'=>'<h3>'+array::join(children[].text,'')+ '</h3>',style=='blockquote'=>'<blockquote>'+array::join(children[].text,'')+ '</blockquote>','<p>'+array::join(children[].text,'')+ '</p>')}.h,''),content)":"content"},
      seo
    }`,{slug:e})},fetchStartContent(){return sanityFetch(`*[_type == "startContent"][0]{
      ...,
      "s1ImageUrl": s1Image.asset->url + "?w=900&auto=format&q=85",
      "s2ImageUrl": s2Image.asset->url + "?w=900&auto=format&q=85",
      "s5ImageUrl": s5Image.asset->url + "?w=900&auto=format&q=85"
    }`)},fetchMustEats(){return sanityFetch(`*[_type == "mustEat"] | order(order asc) {
      _id,
      dish,
      restaurant,
      district,
      price,
      "imageUrl": image.asset->url + "?w=600&auto=format&q=80",
      order
    }`)},fetchCardPacks(){return sanityFetch(`*[_type == "cardPack"] | order(order asc) {
      _id, title, titleDe,
      "slug": slug.current,
      packType,
      "coverImageUrl": coverImage.asset->url + "?w=400&auto=format&q=80",
      price,
      "cards": cards[]{
        "imageUrl": image.asset->url + "?w=600&auto=format&q=80",
        dish, restaurant, district, "cardPrice": price
      },
      order
    }`)},fetchRestaurants(){return sanityFetch(`*[_type == "restaurant"] | order(name asc) {
      _id,
      name,
      district,
      address,
      categories,
      price,
      lat,
      lng,
      mapsUrl,
      website,
      reservationUrl,
      openingHours,
      tip,
      "photo": image.asset->url + "?w=800&auto=format&q=80"
    }`)},fetchHeroSettings(){return sanityFetch(`*[_type == "heroSettings"][0] {
      tagline,
      "desktopImageUrl": desktopImage.asset->url + "?w=1920&auto=format&q=85",
      "mobileImageUrl": mobileImage.asset->url + "?w=900&auto=format&q=85"
    }`)},imageUrl:sanityImageUrl,async fetchStaticPage(e){if(!["about","contact","press","impressum","datenschutz","agb"].includes(e))return null;const t=`*[_type == "staticPage" && slug.current == "${e}"][0]{ title, titleDe, body, bodyDe }`;return sanityFetch(t)}};
